    static let brands: [String] = {
        var seen = Set<String>()
        var result = [String]()
        for r in all { if seen.insert(r.brandName).inserted { result.append(r.brandName) } }
        return result.sorted()
    }()

    static func search(query: String) -> [EquipmentRecord] {
        guard !query.isEmpty else { return [] }
        let q = query.lowercased()
        return all.filter {
            $0.machineName.lowercased().contains(q) ||
            $0.brandName.lowercased().contains(q) ||
            $0.modelSeries.lowercased().contains(q)
        }
    }

    static func variants(forExercise exerciseName: String) -> [EquipmentRecord] {
        let name = exerciseName.lowercased()
        return all.filter {
            let mn = $0.machineName.lowercased()
            return mn == name || mn.hasSuffix(name) || mn.contains(name)
        }.filter {
            !["Storage", "Cardio"].contains($0.primaryCategory)
        }
    }

    static func find(dedupeKey: String) -> EquipmentRecord? {
        all.first { $0.dedupeKey == dedupeKey }
    }
}